	cin>>n>>g;
	for(int i=1;i<=n;++i)
	{
		cin>>a[i];
	}
	int l=1,r=1,t;
	while(r<=n)
	{
		if(__gcd(g,a[r])!=g)
		{
			l=t+1;
			t=r;
		}
		if(r-l)
		{
			ans+=r-l;
		}
		++r;
	}
	cout<<ans;
	return false;
}
